16	@RequiredArgsConstructor
17	@Slf4j
18	public class GreedySolver implements IGreedySolver {
19	
20	    final ConstraintValidator constraintValidator;
21	    final SolverBuilderHelper solverBuilderHelper;
22	
23	    @Override
24	    public BranchLineSolution findSolution(GeneralInput input, boolean isWithFullCircleRoute) {
25	        List<RouteElement> filteredUnvisitedPO = input.getRouteElements().stream()
26	                .filter(p -> !p.isRoot())
27	                .toList().stream().sorted(Comparator.comparingDouble(RouteElement::getDemand).reversed()).toList();
28	
29	        RouteElement source = input.getRouteElements().stream()
30	                .filter(RouteElement::isRoot).findFirst().orElse(null);
31	        assert source != null;
32	
33	        BranchLineSolution solution = solverBuilderHelper.initSol(input);
34	
35	        List<Truck> trucks = input.getTrucks();
36	        List<Truck> sortedTrucks = trucks.stream()
37	                .sorted(Comparator.comparingDouble(Truck::getCapacity).reversed())
38	                .toList();
39	
40	        int iteration = 0;
41	        int truckIndex = 0;
42	
43	        while (!filteredUnvisitedPO.isEmpty() && truckIndex < sortedTrucks.size()) {
44	            log.info("Greedy iteration: {}", ++iteration);
45	            Truck truck = sortedTrucks.get(truckIndex);
46	
47	            RouteElement furthest = solverBuilderHelper.findFurthestInitialSatisfiedCusIndex(truck, source, filteredUnvisitedPO, input, isWithFullCircleRoute);
48	            if (furthest == null) {
49	                truckIndex++;
50	                continue;
51	            }
52	
53	            Route route = initPossibleRoute(truck, source, furthest, input, isWithFullCircleRoute, false);
54	            filteredUnvisitedPO = solverBuilderHelper.updateUnvisitedPostOffice(filteredUnvisitedPO, furthest);
55	
56	            while (true) {
57	                List<SolverBuilderHelper.Candidate> candidates = solverBuilderHelper.getFeasibleInsertionCandidates(route, filteredUnvisitedPO, truck, input, isWithFullCircleRoute);
58	
59	                if (candidates.isEmpty()) break;
60	
61	                SolverBuilderHelper.Candidate best = candidates.stream().min(Comparator.comparingDouble(c -> c.cost))
62	                        .orElse(null);
63	                route.insertPostOfficeToRoute2(best.insertPosition + 1, best.postOffice);
64	                filteredUnvisitedPO = solverBuilderHelper.updateUnvisitedPostOffice(filteredUnvisitedPO, best.postOffice);
65	            }
66	
67	            solution.addRoute(route);
68	            truckIndex++;
69	        }
70	        log.info("[UNVISITED POS] {} {}", filteredUnvisitedPO.size(),
71	                ColorConstant.RED + filteredUnvisitedPO.stream().map(p -> p.getCode() + "_" + p.getDemand()).collect(Collectors.joining(",")));
72	
73	        solverBuilderHelper.postProcessUnvisitedNodes(filteredUnvisitedPO, sortedTrucks, solution, source, input, isWithFullCircleRoute, false);
74	        if (constraintValidator.checkSatisfiedAllSolutionConstraints(solution, input).isValid()) {
75	            solverBuilderHelper.addEmptyRouteForUnassignedTruck(solution, source, sortedTrucks, input, isWithFullCircleRoute);
76	            solution.setFeasible(true);
77	            return solution;
78	        } else {
79	            log.error("No solution found!");
80	            return new BranchLineSolution();
81	        }
82	    }
83	
84	    @Override
85	    public BranchLineSolution findSolutionPickupCombined(GeneralInput input, boolean isWithFullCircleRoute) {
86	        RouteElement source = input.getRouteElements().stream()
87	                .filter(RouteElement::isRoot).findFirst().orElse(null);
88	        assert source != null;
89	        List<RouteElement> unvisited = input.getRouteElements().stream().filter(p -> !p.isRoot()).toList();
90	        BranchLineSolution solution = solverBuilderHelper.initSol(input);
