92	                .sorted(Comparator.comparingDouble(Truck::getCapacity).reversed())
93	                .toList();
94	
95	        unvisited = addFullCircleRoutes(solution, unvisited, sortedTrucks, source, input, isWithFullCircleRoute);
96	
97	        solverBuilderHelper.postProcessUnvisitedNodes(unvisited, sortedTrucks, solution, source, input, isWithFullCircleRoute, true);
98	        if (constraintValidator.checkSatisfiedAllSolutionConstraints(solution, input).isValid()) {
99	            solverBuilderHelper.addEmptyRouteForUnassignedTruckV2(solution, source, input.getTrucks(), input, isWithFullCircleRoute);
100	            solution.setFeasible(true);
101	            return solution;
102	        } else {
103	            log.error("No solution found!");
104	            return new BranchLineSolution();
105	        }
106	    }
