108	    @Override
109	    public BranchLineSolution findSolutionPickupCombined2(GeneralInput input, boolean isWithFullCircleRoute) {
110	        RouteElement source = input.getRouteElements().stream().filter(RouteElement::isRoot).findFirst().orElse(null);
111	        assert source != null;
112	
113	        List<RouteElement> unvisited = input.getRouteElements().stream().filter(p -> !p.isRoot()).toList();
114	        BranchLineSolution solution = solverBuilderHelper.initSol(input);
115	
116	        List<Truck> trucks = input.getTrucks();
117	
118	        unvisited = addImprovedInitialRoutes(solution, unvisited, trucks, source, input, isWithFullCircleRoute);
119	
120	        solverBuilderHelper.postProcessUnvisitedNodes(unvisited, trucks, solution, source, input, isWithFullCircleRoute, true);
121	
122	        if (constraintValidator.checkSatisfiedAllSolutionConstraints(solution, input).isValid()) {
123	            solverBuilderHelper.addEmptyRouteForUnassignedTruckV2(solution, source, input.getTrucks(), input, isWithFullCircleRoute);
124	            solution.setFeasible(true);
125	            return solution;
126	        } else {
127	            log.error("No solution found!");
128	            return new BranchLineSolution();
129	        }
