132	    public List<RouteElement> addImprovedInitialRoutes(BranchLineSolution solution, List<RouteElement> unvisited,
133	                                                       List<Truck> trucks, RouteElement source, GeneralInput input,
134	                                                       boolean isWithFullCircleRoute) {
135	        int iteration = 0;
136	
137	        List<RouteElement> remaining = new ArrayList<>(unvisited);
138	        Set<String> usedTrucks = new HashSet<>();
139	
140	        while (!remaining.isEmpty() && usedTrucks.size() < trucks.size()) {
141	            log.info("Greedy iteration: {}", ++iteration);
142	
143	            RouteElement seed = solverBuilderHelper.findBestSeedPostOffice(remaining, source, input).clone();
144	            if (seed == null) break;
145	
146	            Truck bestTruck = solverBuilderHelper.selectBestTruck(seed, trucks, usedTrucks);
147	            if (bestTruck == null) break;
148	            usedTrucks.add(bestTruck.getVehiclePlate());
149	
150	            Route route = initPossibleRoute(bestTruck, source, seed, input, isWithFullCircleRoute, true);
151	            remaining = solverBuilderHelper.updateUnvisitedPostOfficeV2(remaining, seed);
152	
153	            while (true) {
154	                List<SolverBuilderHelper.Candidate> candidates = solverBuilderHelper.getFeasibleInsertionCandidates(
155	                        route, remaining, bestTruck, input, isWithFullCircleRoute);
156	
157	                if (candidates.isEmpty()) break;
158	
159	                SolverBuilderHelper.Candidate best = candidates.stream()
160	                        .min(Comparator.comparingDouble(c -> c.cost)) // cost is now deltaCost
161	                        .orElse(null);
162	                route.insertPostOfficeToRoute2(best.insertPosition + 1, best.postOffice);
163	                remaining = solverBuilderHelper.updateUnvisitedPostOfficeV2(remaining, best.postOffice);
164	            }
165	
166	            solution.addRoute(route);
167	        }
168	
169	        return remaining;
170	    }
171	
172	    public List<RouteElement> addFullCircleRoutes(BranchLineSolution solution, List<RouteElement> unvisited, List<Truck> trucks, RouteElement source, GeneralInput input, Boolean isWithFullCircleRoute) {
173	        int iteration = 0;
174	        int truckIndex = 0;
175	        while (!unvisited.isEmpty() && truckIndex < trucks.size()) {
176	            log.info("Greedy iteration: {}", ++iteration);
177	            Truck truck = trucks.get(truckIndex);
178	
179	            RouteElement furthest = solverBuilderHelper.findFurthestInitialSatisfiedCusIndexV2(truck, source, unvisited, input, isWithFullCircleRoute);
180	            if (furthest == null) {
181	                truckIndex++;
182	                continue;
183	            }
184	
185	            Route route = initPossibleRoute(truck, source, furthest, input, isWithFullCircleRoute, true);
186	            unvisited = solverBuilderHelper.updateUnvisitedPostOfficeV2(unvisited, furthest);
187	
188	            while (true) {
189	                List<SolverBuilderHelper.Candidate> candidates = solverBuilderHelper.getFeasibleInsertionCandidates(route, unvisited, truck, input, isWithFullCircleRoute);
190	
191	                if (candidates.isEmpty()) break;
192	
193	                SolverBuilderHelper.Candidate best = candidates.stream().min(Comparator.comparingDouble(c -> c.cost))
194	                        .orElse(null);
195	                route.insertPostOfficeToRoute2(best.insertPosition + 1, best.postOffice);
196	                unvisited = solverBuilderHelper.updateUnvisitedPostOfficeV2(unvisited, best.postOffice);
197	            }
198	
199	            solution.addRoute(route);
200	            truckIndex++;
201	        }
202	        return unvisited;
203	    }
204	}
