package com.viettelpost.platform.stms.routing.service.solver.hubandspoke;

import com.viettelpost.platform.stms.common.entity.*;
import com.viettelpost.platform.stms.common.entity.constant.ColorConstant;
import com.viettelpost.platform.stms.routing.service.constraint.hubandspoke.implement.ConstraintValidator;
import jakarta.enterprise.context.ApplicationScoped;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;

import java.util.*;
import java.util.stream.Collectors;

import static com.viettelpost.platform.stms.common.entity.Route.initPossibleRoute;

@ApplicationScoped
@RequiredArgsConstructor
@Slf4j
public class GreedySolver implements IGreedySolver {

    final ConstraintValidator constraintValidator;
    final SolverBuilderHelper solverBuilderHelper;

    @Override
    public BranchLineSolution findSolution(GeneralInput input, boolean isWithFullCircleRoute) {
        List<RouteElement> filteredUnvisitedPO = input.getRouteElements().stream()
                .filter(p -> !p.isRoot())
                .toList().stream().sorted(Comparator.comparingDouble(RouteElement::getDemand).reversed()).toList();

        RouteElement source = input.getRouteElements().stream()
                .filter(RouteElement::isRoot).findFirst().orElse(null);
        assert source != null;

        BranchLineSolution solution = solverBuilderHelper.initSol(input);

        List<Truck> trucks = input.getTrucks();
        List<Truck> sortedTrucks = trucks.stream()
                .sorted(Comparator.comparingDouble(Truck::getCapacity).reversed())
                .toList();

        int iteration = 0;
        int truckIndex = 0;

        while (!filteredUnvisitedPO.isEmpty() && truckIndex < sortedTrucks.size()) {
            log.info("Greedy iteration: {}", ++iteration);
            Truck truck = sortedTrucks.get(truckIndex);

            RouteElement furthest = solverBuilderHelper.findFurthestInitialSatisfiedCusIndex(truck, source, filteredUnvisitedPO, input, isWithFullCircleRoute);
            if (furthest == null) {
                truckIndex++;
                continue;
            }

            Route route = initPossibleRoute(truck, source, furthest, input, isWithFullCircleRoute, false);
            filteredUnvisitedPO = solverBuilderHelper.updateUnvisitedPostOffice(filteredUnvisitedPO, furthest);

            while (true) {
                List<SolverBuilderHelper.Candidate> candidates = solverBuilderHelper.getFeasibleInsertionCandidates(route, filteredUnvisitedPO, truck, input, isWithFullCircleRoute);

                if (candidates.isEmpty()) break;

                SolverBuilderHelper.Candidate best = candidates.stream().min(Comparator.comparingDouble(c -> c.cost))
                        .orElse(null);
                route.insertPostOfficeToRoute2(best.insertPosition + 1, best.postOffice);
                filteredUnvisitedPO = solverBuilderHelper.updateUnvisitedPostOffice(filteredUnvisitedPO, best.postOffice);
            }

            solution.addRoute(route);
            truckIndex++;
        }
        log.info("[UNVISITED POS] {} {}", filteredUnvisitedPO.size(),
                ColorConstant.RED + filteredUnvisitedPO.stream().map(p -> p.getCode() + "_" + p.getDemand()).collect(Collectors.joining(",")));

        solverBuilderHelper.postProcessUnvisitedNodes(filteredUnvisitedPO, sortedTrucks, solution, source, input, isWithFullCircleRoute, false);
        if (constraintValidator.checkSatisfiedAllSolutionConstraints(solution, input).isValid()) {
            solverBuilderHelper.addEmptyRouteForUnassignedTruck(solution, source, sortedTrucks, input, isWithFullCircleRoute);
            solution.setFeasible(true);
            return solution;
        } else {
            log.error("No solution found!");
            return new BranchLineSolution();
        }
    }

    @Override
    public BranchLineSolution findSolutionPickupCombined(GeneralInput input, boolean isWithFullCircleRoute) {
        RouteElement source = input.getRouteElements().stream()
                .filter(RouteElement::isRoot).findFirst().orElse(null);
        assert source != null;
        List<RouteElement> unvisited = input.getRouteElements().stream().filter(p -> !p.isRoot()).toList();
        BranchLineSolution solution = solverBuilderHelper.initSol(input);
        List<Truck> sortedTrucks = input.getTrucks().stream()
                .sorted(Comparator.comparingDouble(Truck::getCapacity).reversed())
                .toList();

        unvisited = addFullCircleRoutes(solution, unvisited, sortedTrucks, source, input, isWithFullCircleRoute);

        solverBuilderHelper.postProcessUnvisitedNodes(unvisited, sortedTrucks, solution, source, input, isWithFullCircleRoute, true);
        if (constraintValidator.checkSatisfiedAllSolutionConstraints(solution, input).isValid()) {
            solverBuilderHelper.addEmptyRouteForUnassignedTruckV2(solution, source, input.getTrucks(), input, isWithFullCircleRoute);
            solution.setFeasible(true);
            return solution;
        } else {
            log.error("No solution found!");
            return new BranchLineSolution();
        }
    }

    @Override
    public BranchLineSolution findSolutionPickupCombined2(GeneralInput input, boolean isWithFullCircleRoute) {
        RouteElement source = input.getRouteElements().stream().filter(RouteElement::isRoot).findFirst().orElse(null);
        assert source != null;

        List<RouteElement> unvisited = input.getRouteElements().stream().filter(p -> !p.isRoot()).toList();
        BranchLineSolution solution = solverBuilderHelper.initSol(input);

        List<Truck> trucks = input.getTrucks();

        unvisited = addImprovedInitialRoutes(solution, unvisited, trucks, source, input, isWithFullCircleRoute);

        solverBuilderHelper.postProcessUnvisitedNodes(unvisited, trucks, solution, source, input, isWithFullCircleRoute, true);

        if (constraintValidator.checkSatisfiedAllSolutionConstraints(solution, input).isValid()) {
            solverBuilderHelper.addEmptyRouteForUnassignedTruckV2(solution, source, input.getTrucks(), input, isWithFullCircleRoute);
            solution.setFeasible(true);
            return solution;
        } else {
            log.error("No solution found!");
            return new BranchLineSolution();
        }
    }

    public List<RouteElement> addImprovedInitialRoutes(BranchLineSolution solution, List<RouteElement> unvisited,
                                                       List<Truck> trucks, RouteElement source, GeneralInput input,
                                                       boolean isWithFullCircleRoute) {
        int iteration = 0;

        List<RouteElement> remaining = new ArrayList<>(unvisited);
        Set<String> usedTrucks = new HashSet<>();

        while (!remaining.isEmpty() && usedTrucks.size() < trucks.size()) {
            log.info("Greedy iteration: {}", ++iteration);

            RouteElement seed = solverBuilderHelper.findBestSeedPostOffice(remaining, source, input).clone();
            if (seed == null) break;

            Truck bestTruck = solverBuilderHelper.selectBestTruck(seed, trucks, usedTrucks);
            if (bestTruck == null) break;
            usedTrucks.add(bestTruck.getVehiclePlate());

            Route route = initPossibleRoute(bestTruck, source, seed, input, isWithFullCircleRoute, true);
            remaining = solverBuilderHelper.updateUnvisitedPostOfficeV2(remaining, seed);

            while (true) {
                List<SolverBuilderHelper.Candidate> candidates = solverBuilderHelper.getFeasibleInsertionCandidates(
                        route, remaining, bestTruck, input, isWithFullCircleRoute);

                if (candidates.isEmpty()) break;

                SolverBuilderHelper.Candidate best = candidates.stream()
                        .min(Comparator.comparingDouble(c -> c.cost)) // cost is now deltaCost
                        .orElse(null);
                route.insertPostOfficeToRoute2(best.insertPosition + 1, best.postOffice);
                remaining = solverBuilderHelper.updateUnvisitedPostOfficeV2(remaining, best.postOffice);
            }

            solution.addRoute(route);
        }

        return remaining;
    }

    public List<RouteElement> addFullCircleRoutes(BranchLineSolution solution, List<RouteElement> unvisited, List<Truck> trucks, RouteElement source, GeneralInput input, Boolean isWithFullCircleRoute) {
        int iteration = 0;
        int truckIndex = 0;
        while (!unvisited.isEmpty() && truckIndex < trucks.size()) {
            log.info("Greedy iteration: {}", ++iteration);
            Truck truck = trucks.get(truckIndex);

            RouteElement furthest = solverBuilderHelper.findFurthestInitialSatisfiedCusIndexV2(truck, source, unvisited, input, isWithFullCircleRoute);
            if (furthest == null) {
                truckIndex++;
                continue;
            }

            Route route = initPossibleRoute(truck, source, furthest, input, isWithFullCircleRoute, true);
            unvisited = solverBuilderHelper.updateUnvisitedPostOfficeV2(unvisited, furthest);

            while (true) {
                List<SolverBuilderHelper.Candidate> candidates = solverBuilderHelper.getFeasibleInsertionCandidates(route, unvisited, truck, input, isWithFullCircleRoute);

                if (candidates.isEmpty()) break;

                SolverBuilderHelper.Candidate best = candidates.stream().min(Comparator.comparingDouble(c -> c.cost))
                        .orElse(null);
                route.insertPostOfficeToRoute2(best.insertPosition + 1, best.postOffice);
                unvisited = solverBuilderHelper.updateUnvisitedPostOfficeV2(unvisited, best.postOffice);
            }

            solution.addRoute(route);
            truckIndex++;
        }
        return unvisited;
    }
}

