package com.viettelpost.platform.stms.routing.service.solver.hubandspoke;

import com.viettelpost.platform.stms.common.entity.BranchLineSolution;
import com.viettelpost.platform.stms.common.entity.GeneralInput;
import com.viettelpost.platform.stms.common.entity.TabuList;
import com.viettelpost.platform.stms.common.entity.enums.Algorithm;
import com.viettelpost.platform.stms.routing.service.operator.hubandspoke.AbstractOperator;
import com.viettelpost.platform.stms.routing.service.operator.hubandspoke.OperatorProducer;
import jakarta.enterprise.context.ApplicationScoped;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.eclipse.microprofile.config.inject.ConfigProperty;

import java.time.Duration;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Objects;

import static com.viettelpost.platform.stms.common.entity.constant.ColorConstant.*;


@ApplicationScoped
@Slf4j
@RequiredArgsConstructor
public class TabuSearchSolver {

    final OperatorProducer operatorProducer;

    @ConfigProperty(name = "algorithm.max.non_improve_iteration")
    int MAX_NON_IMPROVE_ITERATION;
    @ConfigProperty(name = "algorithm.max.tabu_tenure")
    int MAX_TABU_TENURE;
    @ConfigProperty(name = "algorithm.min.tabu_tenure")
    int MIN_TABU_TENURE;
    @ConfigProperty(name = "algorithm.default.tabu_tenure")
    int DEFAULT_TABU_TENURE;
    @ConfigProperty(name = "algorithm.default.shake_tenure")
    int SHAKE_TENURE;
    @ConfigProperty(name = "algorithm.default.shake_size")
    int SHAKE_SIZE;
    @ConfigProperty(name = "algorithm.default.shake_tenure_step")
    int SHAKE_TENURE_STEP;
    @ConfigProperty(name = "algorithm.default.shake_size_step")
    int SHAKE_SIZE_STEP;
    @ConfigProperty(name = "algorithm.default.tabu_decay_rate")
    double TABU_DECAY_RATE;

    public BranchLineSolution findSolution(BranchLineSolution initSolution, GeneralInput input, Integer maxIteration,
                                           Integer minuteTimeLimit)
            throws Exception {
        LocalDateTime startSearchingTime = LocalDateTime.now();
        if (initSolution.isEmptySolution()) {
            return initSolution;
        }
        int nonImproveIteration = 0;
        boolean isRandom = false;
        int tabuTenure = DEFAULT_TABU_TENURE;
        int shakeIter = 0;
        int shakeTenure = SHAKE_TENURE;
        int shakeSize = SHAKE_SIZE;
        int iteration = 0;
        BranchLineSolution currSolution = initSolution;
        double currCost = currSolution.calculateTotalCost();
        TabuList tabuList = new TabuList(input.getRouteElements().size() + 1, DEFAULT_TABU_TENURE);
        double bestCost = currCost;
        BranchLineSolution bestSolution = currSolution;
        List<AbstractOperator> operators = operatorProducer.produceNewOperators()
                .stream().filter(AbstractOperator::isActive).toList();
        while (iteration < maxIteration
                && Math.abs(Duration.between(LocalDateTime.now(), startSearchingTime).toMinutes())
                < minuteTimeLimit) {
            log.debug(PURPLE + "Target node: {}, Iteration: {}, Tabu list size: {}", initSolution.getRoot(),
                    ++iteration, tabuList.getTabuList1().size());
            AbstractOperator bestOperatorStar = null;
            BranchLineSolution bestSolutionStar = new BranchLineSolution();
            for (AbstractOperator operator : operators) {
                operator.build(currSolution);
                log.debug(YELLOW + "Operator: {}", operator.named());
                BranchLineSolution sol = operator.select(isRandom, bestCost,
                        tabuList, iteration);
                if (Objects.isNull(sol)) {
                    log.debug(BLUE + "Null solution!" + RESET);
                    continue;
                }
                if (sol.calculateTotalCost() < bestSolutionStar.calculateTotalCost()) {
                    bestSolutionStar = sol;
                    bestOperatorStar = operator;
                }
            }
            for (AbstractOperator operator : operators) {
                operator.dumpListNeighbor();
            }
            if (Objects.isNull(bestSolutionStar.getRoutes()) || bestSolutionStar.getRoutes()
                    .isEmpty()) {
                tabuTenure = decreaseTabuTenure(tabuTenure);
                continue;
            }

            tabuTenure = adjustTabuTenure(iteration, nonImproveIteration, tabuTenure);

            if (Objects.isNull(bestOperatorStar)
                    || Objects.isNull(bestOperatorStar.getBestOperationPoint())) {
                continue;
            }
            log.debug(CYAN + "Tabu tenure: " + tabuTenure);
            tabuList.addToTabuList1(bestOperatorStar.getBestOperationPoint().getNodes(),
                    iteration, tabuTenure);
            tabuList.addToTabuList2(bestOperatorStar.getBestOperationPoint().getTabuEdges(),
                    iteration, tabuTenure);

            currSolution = bestSolutionStar;
            log.debug(bestOperatorStar.logBestSolution());
            log.debug(currSolution.summary());

            BranchLineSolution tempBestSolution = (BranchLineSolution) currSolution.clone();

            if (tempBestSolution.calculateTotalCost() < bestCost) {
                log.info(
                        GREEN + "Set new best solution: " + tempBestSolution.calculateTotalCost() + RESET);
                bestCost = tempBestSolution.calculateTotalCost();
                bestSolution = tempBestSolution;
                bestSolution.setAlgorithm(Algorithm.TABU_SEARCH);
            }

            if (!isRandom) {
                if (tempBestSolution.calculateTotalCost() < bestCost) {
                    nonImproveIteration = 0;
                } else {
                    nonImproveIteration++;
                }
            }
            if (nonImproveIteration == shakeTenure) {
                isRandom = true;
                shakeIter++;
                if (shakeIter == shakeSize) {
                    isRandom = false;
                    shakeIter = 0;
                    nonImproveIteration = 0;
                    shakeTenure = shakeTenure + SHAKE_TENURE_STEP;
                    shakeSize = shakeSize + SHAKE_SIZE_STEP;
                }
            }
            log.debug(BLUE + "Is random? " + (isRandom ? YELLOW + "Yes" : CYAN + "No"));
        }
        tabuList.clear();
        return bestSolution;
    }

    private int adjustTabuTenure(int iteration, int nonImproveIter, int currTabuTenure) {
        if (iteration % 50 == 0) {
            if (nonImproveIter >= MAX_NON_IMPROVE_ITERATION) {
                return decreaseTabuTenure(currTabuTenure);  // For exploitation
            } else {
                return increaseTabuTenure(currTabuTenure); // For exploration
            }
        } else {
            return currTabuTenure;
        }
    }

    private int increaseTabuTenure(int currTabuTenure) {
        return (int) Math.min(MAX_TABU_TENURE, currTabuTenure * (2 - TABU_DECAY_RATE));
    }

    private int decreaseTabuTenure(int currTabuTenure) {
        return (int) Math.max(MIN_TABU_TENURE, currTabuTenure * TABU_DECAY_RATE);
    }
}

