        splitRouteRecursively(route, input, splitRoutes);
        if (splitRoutes.size() <= 1) {
            return Collections.singletonList(route);
        }
        return splitRoutes;
    }

    private void splitRouteRecursively(Route route, GeneralInput input, List<Route> splitRoutes) {
        log.warn("Splitting multiple time here: {}", route.getRouteElementList().stream().map(RouteElement::getCode)
