package com.viettelpost.platform.stms.routing.service.operator.hubandspoke;

import com.viettelpost.platform.stms.routing.service.operator.hubandspoke.implement.post_operator.*;
import jakarta.enterprise.context.ApplicationScoped;
import jakarta.enterprise.inject.Produces;
import jakarta.inject.Inject;

import java.util.List;

@ApplicationScoped
public class PostSolutionOperatorProducer {
    @Inject
    RemoveEmptyRouteOperator removeEmptyRouteOperator;
    @Inject
    ReAllocateVehicleOperator reAllocateVehicleOperator;
    @Inject
    ShiftTimeToBestFillRateOperator shiftTimeToBestFillRateOperator;
    @Inject
    DetermineStartingTimeDeliveryOperator determineStartingTimeDeliveryOperator;
    @Inject
    MarkProcessedOrderOperator markProcessedOrderOperator;
    @Inject
    AppendPickupPoOperator appendPickupPoOperator;
    @Inject
    AppendDeliveryPoOperator appendDeliveryPoOperator;
    @Inject
    DemandAnalysisOperator demandAnalysisOperator;
    @Inject
    DispatchLatePickupTripOperator dispatchLatePickupTripOperator;
    @Inject
    AddFullCircleRouteOperator addFullCircleRouteOperator;

    @Produces
    public PostOperatorPipeline producePipeline() {
        return new PostOperatorPipeline(List.of(
                removeEmptyRouteOperator,
                reAllocateVehicleOperator,
                shiftTimeToBestFillRateOperator,
                determineStartingTimeDeliveryOperator,
                markProcessedOrderOperator,
                appendDeliveryPoOperator,
                appendPickupPoOperator,
                demandAnalysisOperator,
                dispatchLatePickupTripOperator,
                addFullCircleRouteOperator
        ));
    }

    @Produces
    public PostOperatorPipeline produceOneWayPipeline() {
        return new PostOperatorPipeline(List.of(
                removeEmptyRouteOperator,
                reAllocateVehicleOperator,
                determineStartingTimeDeliveryOperator,
                appendDeliveryPoOperator,
                appendPickupPoOperator,
                demandAnalysisOperator,
                dispatchLatePickupTripOperator
        ));
    }
}
